const todo = {
  todos: JSON.parse(localStorage.getItem('todos')) || [],

  add(text) {
    this.todos.push({ id: Date.now(), text, done: false });
    this.save(); this.render();
  },
  toggle(id) {
    const t = this.todos.find(t => t.id === id);
    if (t) { t.done = !t.done; this.save(); this.render(); }
  },
  remove(id) {
    this.todos = this.todos.filter(t => t.id !== id);
    this.save(); this.render();
  },
  save() { localStorage.setItem('todos', JSON.stringify(this.todos)); },

  render() {
    const list = document.querySelector('#todo-list');
    list.innerHTML = this.todos.map(t => `<li class="${t.done ? 'done' : ''}"><span>${t.text}</span></li>`).join('');
  }
};
todo.render();

