#include <stdio.h>

int factorial(int n);
void swap(int *a, int *b);

int main() {
    printf("Factorial(5): %d\n", factorial(5));
    int x = 10, y = 20;
    swap(&x, &y);
    return 0;
}

int factorial(int n) {
    if (n <= 1) return 1;
    return n * factorial(n - 1);
}

void swap(int *a, int *b) {
    int temp = *a;
    *a = *b;
    *b = temp;
}

#include <stdio.h>

double add(double a, double b) { return a + b; }
double sub(double a, double b) { return a - b; }
double mul(double a, double b) { return a * b; }
double divide(double a, double b) {
    if (b == 0) { printf("Error\n"); return 0; }
    return a / b;
}

int main() {
    char op; double a, b;
    while (1) {
        printf("Op (+, -, *, /, q): ");
        scanf(" %c", &op);
        if (op == 'q') break;
        printf("Two numbers: ");
        scanf("%lf %lf", &a, &b);
        switch (op) {
            case '+': printf("%.2f\n", add(a,b)); break;
            case '-': printf("%.2f\n", sub(a,b)); break;
            case '*': printf("%.2f\n", mul(a,b)); break;
            case '/': printf("%.2f\n", divide(a,b)); break;
        }
    }
    return 0;
}

