#include <iostream>
#include <memory>
using namespace std;

class Resource {
public:
    Resource() { cout << "Acquired\n"; }
    ~Resource() { cout << "Released\n"; }
    void work() { cout << "Working\n"; }
};

int main() {
    Resource* raw = new Resource();
    raw->work();
    delete raw;

    unique_ptr<Resource> uptr = make_unique<Resource>();
    uptr->work();

    shared_ptr<Resource> sptr1 = make_shared<Resource>();
    shared_ptr<Resource> sptr2 = sptr1;
    cout << "Count: " << sptr1.use_count() << endl;
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <fstream>
#include <algorithm>
using namespace std;

class Todo {
    struct Task { string desc; bool done; };
    vector<Task> tasks;
public:
    void add(const string& d) { tasks.push_back({d, false}); }
    void toggle(int i) { if (i>=0&&i<tasks.size()) tasks[i].done=!tasks[i].done; }
    void remove(int i) { if (i>=0&&i<tasks.size()) tasks.erase(tasks.begin()+i); }
    void display() {
        for (size_t i=0; i<tasks.size(); i++) {
            cout << i+1 << ". [" << (tasks[i].done?'X':' ') << "] " << tasks[i].desc << endl;
        }
    }
    void save(const string& file) {
        ofstream ofs(file);
        for (auto& t : tasks) ofs << t.desc << "|" << t.done << endl;
    }
    void load(const string& file) {
        ifstream ifs(file); string line;
        while (getline(ifs, line)) {
            auto sep = line.find('|');
            if (sep != string::npos)
                tasks.push_back({line.substr(0,sep), line.substr(sep+1)=="1"});
        }
    }
};

