      </button>
    </div>
  );
}

import { useState, useCallback } from 'react';
import { useLocalStorage } from './hooks/useLocalStorage';

type Task = {
  id: string;
  title: string;
  completed: boolean;
  priority: 'low' | 'medium' | 'high';
  createdAt: Date;
};

function useTasks() {
  const [tasks, setTasks] = useLocalStorage<Task[]>('tasks', []);

  const addTask = useCallback((title: string, priority: Task['priority']) => {
    setTasks(prev => [...prev, {
      id: crypto.randomUUID(),
      title,
      completed: false,
      priority,
      createdAt: new Date()
    }]);
  }, [setTasks]);

  const toggleTask = useCallback((id: string) => {
    setTasks(prev => prev.map(t =>
      t.id === id ? { ...t, completed: !t.completed } : t
    ));
  }, [setTasks]);

  const deleteTask = useCallback((id: string) => {
    setTasks(prev => prev.filter(t => t.id !== id));
  }, [setTasks]);

  const filteredTasks = useCallback((status: 'all' | 'active' | 'completed') => {
    if (status === 'active') return tasks.filter(t => !t.completed);
    if (status === 'completed') return tasks.filter(t => t.completed);
    return tasks;
  }, [tasks]);

  return { tasks, addTask, toggleTask, deleteTask, filteredTasks };
}

function TaskItem({ task, onToggle, onDelete }: {
  task: Task;
  onToggle: (id: string) => void;
  onDelete: (id: string) => void;
}) {
  return (
    <div className={`task priority-${task.priority}`}>
      <input type="checkbox" checked={task.completed} onChange={() => onToggle(task.id)} />
      <span style={{ textDecoration: task.completed ? 'line-through' : 'none' }}>{task.title}</span>
      <span className="priority-badge">{task.priority}</span>
      <button onClick={() => onDelete(task.id)}>Delete</button>
    </div>
  );
}

export default function App() {
  const { tasks, addTask, toggleTask, deleteTask } = useTasks();
  const [filter, setFilter] = useState<'all' | 'active' | 'completed'>('all');

  return (
    <div className="app">
      <h1>Task Manager</h1>
      <p>Total: {tasks.length} | Active: {tasks.filter(t => !t.completed).length}</p>
      <div>
        {(['all', 'active', 'completed'] as const).map(f => (
          <button key={f} onClick={() => setFilter(f)} className={filter === f ? 'active' : ''}>{f}</button>
        ))}
      </div>
      <div className="task-list">
        {tasks.filter(t => {
          if (filter === 'active') return !t.completed;
          if (filter === 'completed') return t.completed;
          return true;
        }).map(task => (
          <TaskItem key={task.id} task={task} onToggle={toggleTask} onDelete={deleteTask} />
        ))}
      </div>
    </div>
  );
}

