package main
import "testing"
func TestSum(t *testing.T) {
  tests := []struct{
    name string
    input []int
    want int
  }{
    {"empty", []int{}, 0},
    {"multiple", []int{1,2,3}, 6},
  }
  for _, tt := range tests {
    t.Run(tt.name, func(t *testing.T) {
      got := Sum(tt.input)
      if got != tt.want { t.Errorf("got %d, want %d", got, tt.want) }
    })
  }
}
func BenchmarkSum(b *testing.B) {
  nums := []int{1,2,3,4,5}
  for i := 0; i < b.N; i++ { Sum(nums) }
}
func ExampleSum() {
  fmt.Println(Sum([]int{1,2,3}))
  // Output: 6
}

