    fun h1(text: String) {
        children.add(H1(text))
    }
    fun p(text: String) {
        children.add(P(text))
    }
}

class H1(val text: String) : Element("h1")
class P(val text: String) : Element("p")

fun html(init: Html.() -> Unit): Html {
