CREATE PROCEDURE GetOrderStats(
    IN user_id INT,
    OUT total_orders INT,
    OUT total_spent DECIMAL(12,2)
)
BEGIN
    SELECT COUNT(*), IFNULL(SUM(total), 0)
    INTO total_orders, total_spent
    FROM orders
    WHERE customer_id = user_id;
